'use client'

// src/label.web.tsx
import * as Label from "@radix-ui/react-label";
import { Slot } from "@rn-primitives/slot";
import { Pressable, Text as RNText } from "react-native";
var Root2 = ({ asChild, tabIndex = -1, ref, ...props }) => {
  const Component = asChild ? Slot : Pressable;
  return <Component ref={ref} tabIndex={tabIndex} {...props} />;
};
Root2.displayName = "RootWebLabel";
var Text = ({ asChild, nativeID, htmlFor, ref, ...props }) => {
  const Component = asChild ? Slot : RNText;
  return <Label.Root asChild={!htmlFor} id={nativeID} htmlFor={htmlFor}>
      <Component ref={ref} {...props} />
    </Label.Root>;
};
Text.displayName = "TextWebLabel";
export {
  Root2 as Root,
  Text
};
